"""
NIF Item Master data migration — embedded JSON data from 3 NIF Excel files.
Runs on startup in main.py lifespan() if table is empty.

Data sources:
  - GG NIF S24 MOD WK7.xlsx  (2024, effective WK7, 23 items)
  - GG NIF S25 MOD WK7.xlsx  (2025, effective WK7, 15 items)
  - GG NIF S26 MOD WK4.xlsx  (2026, effective WK4, 31 items)

Total: 69 items across 3 event years.
"""
import json
import zlib
import base64
import logging

logger = logging.getLogger("golfgen")

# ── Compressed JSON data (69 items) ──────────────────────────────────────
# Generated by parsing all 3 NIF Excel files.
# Keys: ey=event_year, ew=effective_week, st=item_status, br=brand,
#   mt=mod_type, de=description, wi=wmt_item_number, up=upc,
#   vs=vendor_stock_number, bi=brand_id, wc=wholesale_cost, wr=walmart_retail,
#   vp=vendor_pack, wp=whse_pack, os=old_store_count, ns=new_store_count,
#   sd=store_count_diff, cl=carton_length, cw=carton_width, ch=carton_height,
#   cb=cbm, cf=cbf, co=color, dx=dexterity, ca=category

_COMPRESSED_DATA = ""


def _load_items():
    """Decompress and parse the embedded item data."""
    if _COMPRESSED_DATA is None:
        return []
    raw = zlib.decompress(base64.b64decode(_COMPRESSED_DATA))
    return json.loads(raw)


def run_nif_migration():
    """Load NIF items into walmart_nif_items if table is empty."""
    from core.database import get_db, get_db_rw

    con = get_db()
    try:
        # Check if table exists and has data
        try:
            row = con.execute("SELECT COUNT(*) FROM walmart_nif_items").fetchone()
            if row and row[0] > 0:
                logger.info(f"NIF migration: table already has {row[0]} rows, skipping")
                return
        except Exception:
            logger.info("NIF migration: table doesn't exist yet, will create on next startup")
            return
    finally:
        con.close()

    items = _load_items()
    if not items:
        logger.warning("NIF migration: no embedded data found")
        return

    con = get_db_rw()
    try:
        count = 0
        for item in items:
            try:
                con.execute("""
                    INSERT INTO walmart_nif_items (
                        event_year, effective_week, item_status, description, brand,
                        wmt_item_number, upc, vendor_stock_number, brand_id,
                        wholesale_cost, walmart_retail, vendor_pack, whse_pack,
                        old_store_count, new_store_count, store_count_diff,
                        carton_length, carton_width, carton_height, cbm, cbf,
                        color, dexterity, category, mod_type,
                        division, customer, platform
                    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'golf', 'walmart_stores', 'scintilla')
                """, [
                    item.get("ey"), item.get("ew"), item.get("st"),
                    item.get("de"), item.get("br"),
                    item.get("wi"), item.get("up"), item.get("vs"), item.get("bi"),
                    item.get("wc", 0), item.get("wr", 0),
                    item.get("vp", 0), item.get("wp", 0),
                    item.get("os", 0), item.get("ns", 0), item.get("sd", 0),
                    item.get("cl", 0), item.get("cw", 0), item.get("ch", 0),
                    item.get("cb", 0), item.get("cf", 0),
                    item.get("co"), item.get("dx"),
                    item.get("ca"), item.get("mt"),
                ])
                count += 1
            except Exception as e:
                logger.warning(f"NIF migration: skip item {item.get('de')}: {e}")

        logger.info(f"NIF migration: loaded {count}/{len(items)} items")
    finally:
        con.close()
